import{_ as t,o,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const p=JSON.parse('{"title":"RFC-012 ‚Äî Mars Surface Map ¬∑ technical strategy","description":"","frontmatter":{},"headers":[],"relativePath":"rfc/RFC-012.md","filePath":"rfc/RFC-012.md"}'),s={name:"rfc/RFC-012.md"};function i(n,e,d,c,l,h){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="rfc-012-‚Äî-mars-surface-map-¬∑-technical-strategy" tabindex="-1">RFC-012 ‚Äî Mars Surface Map ¬∑ technical strategy <a class="header-anchor" href="#rfc-012-‚Äî-mars-surface-map-¬∑-technical-strategy" aria-label="Permalink to &quot;RFC-012 ‚Äî Mars Surface Map ¬∑ technical strategy&quot;">‚Äã</a></h1><p><em>Orrery ¬∑ Open RFC ¬∑ v0.1 ¬∑ May 2026</em></p><blockquote><p><strong>Status:</strong> Open <strong>Author:</strong> product <strong>Closes into:</strong> ADR-037 (surface-site shared schema), ADR-038 (Mars 2D projection), ADR-039 (cross-link contract between /mars and /missions) <strong>Slice gate:</strong> v0.4 <strong>Why this is an RFC:</strong> PRD-009 specifies a Mars peer of <code>/moon</code> ‚Äî same panel pattern, same site catalogue shape. The technical questions are about <em>abstraction</em> (do /mars and /moon share a generic SurfaceMap, or stay independent?), <em>projection</em> (the Moon&#39;s near/far-disc 2D view doesn&#39;t translate to Mars cleanly ‚Äî Mars has no permanent far side), and <em>cross-linking</em> (every site is also a mission card; how do we keep the two views from drifting?).</p></blockquote><hr><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">‚Äã</a></h2><p><code>/moon</code> shipped in v0.1 with:</p><ul><li>3D sphere with rotation</li><li>2D toggle: dual-disc near-side / far-side</li><li>Site markers, agency-coloured</li><li>Detail panel: OVERVIEW ¬∑ GALLERY ¬∑ LEARN</li><li>Site-to-mission cross-link via shared <code>id</code></li></ul><p>Mars adds these constraints:</p><ul><li>~16 confirmed surface artefacts (vs Moon&#39;s 16 ‚Äî comparable count)</li><li>No &quot;near side / far side&quot; ‚Äî Mars rotates fully every 24h 39 min and is observed from all sides</li><li>Failed landings are part of the Mars story (Schiaparelli, Beagle 2, Mars 2/3/6) ‚Äî Moon&#39;s catalogue is mostly successful</li><li>Latitude clustering is a story (most successes near the equator due to EDL physics) ‚Äî invisible on a 3D globe but obvious on a 2D map</li><li>Mission cross-link is much stronger than for Moon (every Mars site has a mission card; many Moon sites do too but the linkage was retrofitted)</li></ul><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">‚Äã</a></h2><h3 id="oq-1-‚Äî-generic-surfacemap-component-or-independent-mars-moon" tabindex="-1">OQ-1 ‚Äî Generic SurfaceMap component, or independent /mars + /moon? <a class="header-anchor" href="#oq-1-‚Äî-generic-surfacemap-component-or-independent-mars-moon" aria-label="Permalink to &quot;OQ-1 ‚Äî Generic SurfaceMap component, or independent /mars + /moon?&quot;">‚Äã</a></h3><table tabindex="0"><thead><tr><th>Option</th><th>Code reuse</th><th>Customisation cost</th><th>Risk</th></tr></thead><tbody><tr><td><strong>A. Independent</strong> ‚Äî <code>/mars/+page.svelte</code> is a fork of <code>/moon/+page.svelte</code>, edited for Mars</td><td>0% reuse</td><td>Lowest startup cost</td><td>Drift over time; bug fixes have to be made twice</td></tr><tr><td><strong>B. Generic component</strong> ‚Äî <code>&lt;SurfaceMap body={...} sites={...} /&gt;</code> consumes both Mars + Moon</td><td>~70% reuse</td><td>Initial refactor of /moon (~1 day)</td><td>Coupling: a change to one body&#39;s UI risks the other</td></tr><tr><td><strong>C. Shared schema only</strong> ‚Äî same <code>surface-site.ts</code> type, separate page components</td><td>0% UI reuse, 100% data reuse</td><td>No refactor</td><td>Drift in UI; aligned in data</td></tr></tbody></table><p><strong>Recommendation: B.</strong> The two pages are doing the same thing. A generic component avoids the fork-and-drift problem. The Moon-specific bits (near-side / far-side dual disc) become props (<code>projection: &#39;orthographic-pair&#39; | &#39;equirectangular&#39;</code>) on the generic component. /mars passes <code>&#39;equirectangular&#39;</code>; /moon keeps the dual-disc.</p><p>The refactor is a one-time cost. Subsequent feature work (e.g. adding rover traverses in V1.5) ships once for both.</p><hr><h3 id="oq-2-‚Äî-2d-projection-for-mars" tabindex="-1">OQ-2 ‚Äî 2D projection for Mars <a class="header-anchor" href="#oq-2-‚Äî-2d-projection-for-mars" aria-label="Permalink to &quot;OQ-2 ‚Äî 2D projection for Mars&quot;">‚Äã</a></h3><p>The Moon&#39;s 2D view (orthographic pair: near-side disc + far-side disc) works because Earth-locked tidal rotation makes &quot;near&quot; and &quot;far&quot; semantically meaningful. For Mars, every longitude is equally observable.</p><table tabindex="0"><thead><tr><th>Option</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>A. Equirectangular</strong> (rectangular projection: lat 0‚Ä¶180¬∞, lon 0‚Ä¶360¬∞)</td><td>Simplest; reads like a world map; latitude clustering instantly visible</td><td>Polar distortion (Mars&#39;s poles aren&#39;t rover targets ‚Äî low cost)</td></tr><tr><td><strong>B. Mollweide</strong> (equal-area elliptical)</td><td>Beautiful; fair representation</td><td>Most users don&#39;t know how to read it; pole detail lost</td></tr><tr><td><strong>C. Orthographic pair (eastern hemisphere + western hemisphere)</strong></td><td>Mirrors /moon&#39;s dual-disc visual rhythm</td><td>Nothing about Mars&#39;s geography respects a hemisphere split</td></tr><tr><td><strong>D. Polar-projection toggle</strong> (south-pole disc; north-pole disc)</td><td>Highlights polar landers (Phoenix near 68¬∞N)</td><td>Equatorial sites get crowded near the disc edge</td></tr></tbody></table><p><strong>Recommendation: A ‚Äî Equirectangular.</strong> The latitude-clustering story is the educational payload. Mollweide is prettier but the audience reads world-maps as rectangles. Polar-projection (D) can ship as V1.5 if Phoenix / planned ExoMars-Vikram-class polar work warrants it.</p><p>ADR-038 to lock equirectangular for Mars and reaffirm orthographic-pair for Moon (the projection decision is per-body, not global).</p><hr><h3 id="oq-3-‚Äî-failed-attempt-visual-encoding" tabindex="-1">OQ-3 ‚Äî Failed-attempt visual encoding <a class="header-anchor" href="#oq-3-‚Äî-failed-attempt-visual-encoding" aria-label="Permalink to &quot;OQ-3 ‚Äî Failed-attempt visual encoding&quot;">‚Äã</a></h3><p>Mars catalogue has confirmed-success, partial-success, and confirmed-failure landers, all with known surface positions. Today /moon doesn&#39;t carry this distinction (most Moon entries are successes; the few failures are buried in the description).</p><table tabindex="0"><thead><tr><th>Option</th><th>Encoding</th></tr></thead><tbody><tr><td><strong>A. Same dot, dashed outline for failure</strong></td><td>Dashed white border instead of solid</td></tr><tr><td><strong>B. Same dot, opacity reduction for failure</strong></td><td>60% opacity on the agency colour</td></tr><tr><td><strong>C. Different shape</strong></td><td>Cross or X for failures, disc for success</td></tr><tr><td><strong>D. Two separate legend categories per agency</strong></td><td>&quot;USA ¬∑ success&quot; + &quot;USA ¬∑ failure&quot; rows in the legend</td></tr></tbody></table><p><strong>Recommendation: A ‚Äî Dashed outline.</strong> Carries information without inventing a second visual vocabulary. Legend explains &quot;dashed = mission ended before / during landing.&quot; Applies to /moon too ‚Äî Beresheet, Vikram-on-Chandrayaan-2, etc., become better-encoded.</p><hr><h3 id="oq-4-‚Äî-mars-‚Üî-missions-cross-link-ux" tabindex="-1">OQ-4 ‚Äî <code>/mars</code> ‚Üî <code>/missions</code> cross-link UX <a class="header-anchor" href="#oq-4-‚Äî-mars-‚Üî-missions-cross-link-ux" aria-label="Permalink to &quot;OQ-4 ‚Äî `/mars` ‚Üî `/missions` cross-link UX&quot;">‚Äã</a></h3><p>Every Mars surface site corresponds to a mission card. From the site panel, the user should be able to &quot;open the full mission card.&quot; From the mission card, the user should be able to &quot;see this on the surface.&quot;</p><table tabindex="0"><thead><tr><th>Option</th><th>UX</th></tr></thead><tbody><tr><td><strong>A. Site panel ‚Üí &quot;FULL MISSION CARD&quot; button ‚Üí /missions?id=curiosity</strong></td><td>Existing pattern (FLY-button family)</td></tr><tr><td><strong>B. Site panel ‚Üí embedded mission summary inline</strong></td><td>No navigation; less discoverability of the card itself</td></tr><tr><td><strong>C. Both directions</strong> ‚Äî site ‚Üí card AND card ‚Üí site</td><td>Symmetric but adds a button to /missions cards</td></tr></tbody></table><p><strong>Recommendation: C.</strong> Add a &quot;ON THE SURFACE&quot; chip to mission cards whose mission has a corresponding /mars site. Click navigates to <code>/mars?site=[id]</code>. The reverse direction is the existing FLY/mission-link pattern. Both are URL-addressable and survive deep-link sharing.</p><hr><h3 id="oq-5-‚Äî-when-does-mars-get-added-to-the-nav" tabindex="-1">OQ-5 ‚Äî When does <code>/mars</code> get added to the nav? <a class="header-anchor" href="#oq-5-‚Äî-when-does-mars-get-added-to-the-nav" aria-label="Permalink to &quot;OQ-5 ‚Äî When does `/mars` get added to the nav?&quot;">‚Äã</a></h3><p>The current nav (post v0.4 reorder) is: <code>EXPLORE ‚Üí MISSIONS ‚Üí PLAN ‚Üí FLY ‚Üí EARTH ‚Üí MOON</code></p><p>Adding MARS:</p><ul><li>After MOON (preserves &quot;by destination&quot; cluster after the simulator screens) ‚Äî new tail position</li><li>Before EARTH (preserves rough &quot;size order: Earth ‚Üí Moon ‚Üí Mars&quot; but breaks the existing v0.4 order)</li><li>Between MOON and FLY (breaks the simulator cluster)</li></ul><p><strong>Recommendation: After MOON.</strong> Final order: <code>EXPLORE ‚Üí MISSIONS ‚Üí PLAN ‚Üí FLY ‚Üí EARTH ‚Üí MOON ‚Üí MARS</code>. Story arc: simulators first, then the destination catalogue (Moon prologue ‚Üí Mars main act).</p><hr><h3 id="oq-6-‚Äî-should-rover-traverses-curiosity-perseverance-opportunity-routes-ship-in-v1" tabindex="-1">OQ-6 ‚Äî Should rover traverses (Curiosity / Perseverance / Opportunity routes) ship in V1? <a class="header-anchor" href="#oq-6-‚Äî-should-rover-traverses-curiosity-perseverance-opportunity-routes-ship-in-v1" aria-label="Permalink to &quot;OQ-6 ‚Äî Should rover traverses (Curiosity / Perseverance / Opportunity routes) ship in V1?&quot;">‚Äã</a></h3><p>PRD-009 explicitly defers this. Worth checking: the data is freely available (NASA publishes daily traverse polylines); the visual payoff is significant.</p><table tabindex="0"><thead><tr><th>Option</th><th>Cost</th><th>Payoff</th></tr></thead><tbody><tr><td><strong>A. V1 ships landing-sites only</strong> (per PRD)</td><td>0</td><td>Baseline</td></tr><tr><td><strong>B. V1 ships traverses for the active rovers (Curiosity + Perseverance)</strong></td><td>~2 days additional + ongoing data refresh story</td><td>Big visual payoff; sets up V2 nicely</td></tr><tr><td><strong>C. V1 ships traverses for all completed rovers</strong></td><td>~3 days</td><td>Full picture; some traverses (Opportunity 45 km) are visually striking</td></tr></tbody></table><p><strong>Recommendation: A for V1, B for V1.1.</strong> PRD-009 defers traverses for a reason ‚Äî they&#39;re a separate data discipline (daily updates, attribution chain, route-simplification). Ship the static surface map first; add traverses as a follow-up that doesn&#39;t risk slipping V1.</p><hr><h2 id="decision-criteria" tabindex="-1">Decision criteria <a class="header-anchor" href="#decision-criteria" aria-label="Permalink to &quot;Decision criteria&quot;">‚Äã</a></h2><p>We accept a recommendation when:</p><ol><li>The generic SurfaceMap refactor doesn&#39;t regress /moon (e2e suite passes).</li><li>The Mars 3D + 2D toggle works at 375 px width with no horizontal scroll.</li><li>Cross-link round-trip works: <code>/mars?site=curiosity</code> ‚Üí click &quot;FULL MISSION CARD&quot; ‚Üí <code>/missions?id=curiosity</code> ‚Üí click &quot;ON THE SURFACE&quot; ‚Üí back to <code>/mars?site=curiosity</code>.</li><li>Failed-attempt encoding reads correctly without colour-only cues (accessibility).</li><li>Schema validation (ADR-019) covers <code>mars-sites.json</code> from day one.</li></ol><hr><h2 id="closure-path" tabindex="-1">Closure path <a class="header-anchor" href="#closure-path" aria-label="Permalink to &quot;Closure path&quot;">‚Äã</a></h2><ul><li><strong>ADR-037</strong> ‚Äî Generic SurfaceMap component + shared <code>surface-site.ts</code> type. Refactor /moon onto it.</li><li><strong>ADR-038</strong> ‚Äî Per-body 2D projection: Mars equirectangular, Moon orthographic-pair (status quo). Polar-projection toggle deferred.</li><li><strong>ADR-039</strong> ‚Äî Bidirectional cross-link contract between site panels and mission cards.</li></ul><p>Traverses (OQ-6) deferred to a future RFC if the V1.1 work warrants its own design pass.</p><hr><p><em>Orrery ¬∑ RFC-012 ¬∑ v0.1 ¬∑ Open.</em></p>',52)])])}const m=t(s,[["render",i]]);export{p as __pageData,m as default};
